465   /// changes.
466   bool mergeInValue(ValueLatticeElement &IV, Value *V,
467                     ValueLatticeElement MergeWithV,
468                     ValueLatticeElement::MergeOptions Opts = {
469                         /*MayIncludeUndef=*/false, /*CheckWiden=*/false});
