243                                       SmallPtrSetImpl<Value *> &InsertedValues,
244                                       Statistic &InstRemovedStat,
245                                       Statistic &InstReplacedStat) {
246   bool MadeChanges = false;
247   for (Instruction &Inst : make_early_inc_range(BB)) {
